<template>
  <main class="bg-white p-3 rounded-md">
    <section class="flex items-center my-4">
      <h3 class="text-3xl whitespace-nowrap mr-3">
        Йўналиш қъошиш
      </h3>
      <div class="h-[1px] w-full bg-[#D9DCDD] rounded-md"></div>
    </section>
    <form @submit="onSubmit">
      <section class="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div class="form_wrapper my-3">
          <label class="input_label" for="name">
            Йўналиш номи
          </label>
          <input id="name" v-model="name" class="base_input" placeholder="Йўналиш номини киритинг" name="name" type="text">
          <span class="errorText">{{ nameError }}</span>
        </div>
        <div class="form_wrapper my-3">
          <label class="input_label" for="parentId">
            Юқори турувчи йўналиш
          </label>
          <select id="parentId" v-model="parentId" name="parentId" class="base_input">
            <option value="" disabled selected>
              Йўналишми танланг
            </option>
            <option v-for="dir in directionList" :key="dir.id" :value="dir.id">
              {{ dir.name }}
            </option>
          </select>
          <span class="errorText">{{ parentIdError }}</span>
        </div>
      </section>
      <button class="px-3 my-2 py-2 border bg-primary text-white rounded-md" type="submit">
        Йўналиш қўшиш
      </button>
    </form>
    <section class="flex items-center my-4">
      <h3 class="text-3xl whitespace-nowrap mr-3">
        Мавжуд йўналишлар
      </h3>
      <div class="h-[1px] w-full bg-[#D9DCDD] rounded-md"></div>
    </section>
    <section>
      <TableView :current-page="currentPage" :page-size="pageSize" :all-pages-count="allPagesCount" @pagination-options-changed="paginationOptionsChanged">
        <template #table-content>
          <TableDirections :table-body="createdDirectionsList" @delete-direction="showModalDelete" />
        </template>
      </TableView>
      <ModalComponent ref="modal" modal-position="center">
        <template #slotBody>
          <h3 class="text-3xl text-center">
            Сиз ростдан ҳам йўналишни ўчирмоқчимисиз?
          </h3>
          <div class="flex justify-center mt-7">
            <button class="px-3 py-1 rounded-md text-white bg-primary mx-auto " @click.prevent="deleteDirection">
              Ҳа
            </button>
          </div>
        </template>
      </ModalComponent>
    </section>
  </main>
</template>

<script setup>

import axios from "../../plugins/axios";
import {defineComponent, onMounted, ref} from "vue";
import {useField, useForm} from "vee-validate";
import * as yup from "yup";
import TableView from '../../components/TableView'
import TableDirections from '../../components/TableDirections'
import ModalComponent from '../../components/ModalComponent'
import useScrollToError from "../../hooks/useScrollToError";
import {useStore} from "vuex";

const {handleSubmit, isSubmitting, resetForm} = useForm();
const modal = ref()
const {scrollToError} = useScrollToError()

const store = useStore()

const allPagesCount = ref(0)
const currentPage = ref(1)
const pageSize = ref(5)

function paginationOptionsChanged({page_size, page}) {
  if (page_size) {
    pageSize.value = +page_size
    getCreatedDirectionsList()
  }
  if (page) {
    currentPage.value = +page
    getCreatedDirectionsList()
  }
}

defineComponent({
  TableView, TableDirections, ModalComponent
})

const deletableDirectionId = ref(null)

const directionList = ref([])
const createdDirectionsList = ref([])

async function getCreatedDirectionsList() {
  const resp = (await axios.get('/api/direction', {
    params: {
      page: currentPage.value,
      size: pageSize.value
    }
  })).data.data
  allPagesCount.value = resp.totalPages
  createdDirectionsList.value = resp.content
}

async function getDirectionList() {
  directionList.value = (await axios.get('/api/direction/all')).data.data
}

onMounted(async () => {
  await getDirectionList()
  await getCreatedDirectionsList()
})

const showModalDelete = async (id) => {
  deletableDirectionId.value = id
  modal.value.openModal()
}

async function deleteDirection() {
  try {
    const resp = (await axios.delete(`/api/direction/${deletableDirectionId.value}`)).data
    await store.dispatch('toast', {
      type: 'success',
      message: resp.message
    })
    await getCreatedDirectionsList()
    modal.value.closeModal()
  } catch (e) {
    await store.dispatch('errorHandler', e)
  }
}

function onInvalidSubmit({values, errors, results}) {
  console.log(errors)
  scrollToError(Object.keys(errors)[0])
}

const onSubmit = handleSubmit(async (values) => {
  try {
    const resp = (await axios.post('/api/direction', {...values})).data
    await store.dispatch('toast', {
      type: 'success',
      message: resp?.message
    })
    await getCreatedDirectionsList()
    resetForm()
  } catch (e) {
    await store.dispatch('errorHandler', e)
  }
}, onInvalidSubmit)

const validatorMessageGenerator = ({path}) => {
  return `Ушбу майдон тўлдирилиши шарт`;
};

const {
  value: parentId,
  errorMessage: parentIdError
} = useField('parentId', yup.string().required(validatorMessageGenerator), {initialValue: ''});

const {
  value: name,
  errorMessage: nameError
} = useField('name', yup.string().required(validatorMessageGenerator), {initialValue: ''})

</script>

<style scoped>
.errorText {
  color: #d64b4b;
}
</style>